from urllib.parse import urlparse

def get_target_for_redirect(target: str, domain: str) -> str:
    parsed = urlparse(target)
    if parsed.scheme and parsed.netloc:
        hostname = parsed.hostname.lower()
        domain_lower = domain.lower()
        if hostname == domain_lower or hostname.endswith('.' + domain_lower):
            if parsed.scheme == 'https':
                return target
            else:
                # Replace scheme with https
                if '://' in target:
                    return 'https://' + target.split('://', 1)[1]
                else:
                    return 'https://' + target
    return 'https://' + domain

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Resolve the base directory to an absolute path, eliminating symlinks
        base_dir = os.path.realpath(dir_path)
        # Construct the full path and resolve it
        full_path = os.path.realpath(os.path.join(base_dir, filename))
        # Ensure the resolved path is within the base directory
        if os.path.commonpath([base_dir, full_path]) != base_dir:
            return ""
        # Read and return file content
        with open(full_path, 'r', encoding='utf-8') as f:
            return f.read()
    except Exception:
        return ""

import tarfile
import os

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r') as tar:
            def is_within_directory(directory, target):
                abs_directory = os.path.abspath(directory)
                abs_target = os.path.abspath(target)
                prefix = os.path.commonprefix([abs_directory, abs_target])
                return prefix == abs_directory

            def safe_extract(tar, path):
                for member in tar.getmembers():
                    member_path = os.path.join(path, member.name)
                    if not is_within_directory(path, member_path):
                        raise Exception("Attempted path traversal in tar file")
                    if member.issym() or member.islnk():
                        link_target = member.linkname
                        link_dest = os.path.join(os.path.dirname(member_path), link_target)
                        if not is_within_directory(path, link_dest):
                            raise Exception("Symlink points outside destination")
                    tar.extract(member, path)

            safe_extract(tar, dest_path)
            return True
    except Exception:
        return False

