import ast

def evaluate_expression(expr: str) -> str:
    def _eval_node(node):
        # Handle numbers (Python 3.8+ uses Constant, older uses Num)
        if isinstance(node, (ast.Constant, getattr(ast, 'Num', ()))):
            val = node.value if isinstance(node, ast.Constant) else node.n
            if isinstance(val, (int, float)):
                return val
            raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.UnaryOp):
            operand = _eval_node(node.operand)
            if isinstance(node.op, ast.UAdd):
                return +operand
            elif isinstance(node.op, ast.USub):
                return -operand
            raise ValueError("Unsupported unary operator")
        elif isinstance(node, ast.BinOp):
            left = _eval_node(node.left)
            right = _eval_node(node.right)
            op = node.op
            if isinstance(op, ast.Add):
                return left + right
            elif isinstance(op, ast.Sub):
                return left - right
            elif isinstance(op, ast.Mult):
                return left * right
            elif isinstance(op, ast.Div):
                return left / right
            elif isinstance(op, ast.FloorDiv):
                return left // right
            elif isinstance(op, ast.Mod):
                return left % right
            elif isinstance(op, ast.Pow):
                return left ** right
            raise ValueError("Unsupported binary operator")
        else:
            raise ValueError("Unsupported expression")

    try:
        tree = ast.parse(expr, mode='eval')
        result = _eval_node(tree.body)
        if isinstance(result, (int, float)):
            return str(result)
        return ""
    except Exception:
        return ""

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }
    if info_type not in mapping:
        return header
    # Prevent CRLF injection by removing carriage return and line feed characters
    sanitized = info_content.replace('\r', '').replace('\n', '')
    new_header = header.copy()
    new_header[mapping[info_type]] = sanitized
    return new_header

