from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    """
    Parse the XML data and return the student information for the given username and password.
    """
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    # Iterate over all student elements to find a match
    for student in root.findall("student"):
        # Extract username and password text safely
        username_elem = student.find("username")
        password_elem = student.find("password")
        if username_elem is None or password_elem is None:
            continue
        if username_elem.text == username and password_elem.text == password:
            # Build result dictionary
            result = {}
            for field in ("username", "password", "name", "citizenship", "age"):
                elem = student.find(field)
                if elem is not None and elem.text is not None:
                    result[field] = elem.text
                else:
                    result[field] = ""
            return result
    return None

